<?php
namespace Tests\Feature\Hr; use Illuminate\Support\Facades\Artisan; use Illuminate\Support\Facades\Schema; use Tests\TestCase;
class HrPhase3DMigrationsRollbackTest extends TestCase { use RefreshHrDatabase; public function test_asset_tables_exist():void{$this->assertTrue(Schema::hasColumns('hr_assets',['asset_category_id','asset_code','serial_number','barcode','status']));$this->assertTrue(Schema::hasColumns('hr_asset_assignments',['asset_id','employee_id','assigned_at','returned_at','status']));$this->assertTrue(Schema::hasColumns('hr_asset_events',['asset_id','event_type','from_status','to_status','metadata']));} public function test_rollback_preserves_advances():void{Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback',['--step' => 4]);Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback',['--step'=>4]);Artisan::call('migrate:rollback',['--step'=>4]);Artisan::call('migrate:rollback',['--step'=>5]);Artisan::call('migrate:rollback',['--step'=>3]);Artisan::call('migrate:rollback',['--step'=>5]);Artisan::call('migrate:rollback',['--step'=>6]);Artisan::call('migrate:rollback',['--step'=>2]);Artisan::call('migrate:rollback',['--step'=>4]);$this->assertFalse(Schema::hasTable('hr_assets'));$this->assertTrue(Schema::hasTable('hr_advances'));} }
